#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input span
    hexi::buffer_adaptor<const std::span<const uint8_t>> adaptor(buffer);

    // Create binary_stream using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    NetworkPacket packet;

    // Use operator>> to read packet_id
    stream >> packet.packet_id;

    // Use prefixed adaptor to read username
    stream >> hexi::prefixed(packet.username);

    // Read scores vector using read_container with prefixed adaptor
    stream >> hexi::prefixed(packet.scores);

    // Use null_terminated adaptor to read metadata string
    stream >> hexi::null_terminated(packet.metadata);

    // Use skip() to skip any remaining padding bytes
    if (stream.total_read() < buffer.size()) {
        stream.skip(buffer.size() - stream.total_read());
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input span
    hexi::buffer_adaptor<const std::span<const uint8_t>> adaptor(buffer);

    // Create binary_stream using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    PacketInfo info;

    // Use span() to get zero-copy view of packet_id
    auto packet_id_span = stream.span<uint32_t>(1);
    if (!packet_id_span.empty()) {
        info.packet_id = packet_id_span[0];
    }

    // Use prefixed adaptor to read username as string_view
    stream >> hexi::prefixed(info.username);

    // Read scores vector count and skip data
    uint32_t scores_count = 0;
    stream >> scores_count; // Read the count

    // Skip the scores data
    if (scores_count > 0) {
        stream.skip(scores_count * sizeof(uint32_t));
    }

    return info;
}
