    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Create a binary_stream object using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Calculate required space: header (4 bytes) + items (each 4 bytes)
    const size_t required_space = sizeof(header) + items.size() * sizeof(uint32_t);

    // Check if buffer has enough space for header + items
    // Get current write position and calculate available space
    auto current_write_pos = adaptor.write_ptr() - buffer.data();
    const size_t available_space = buffer.size() - current_write_pos;

    if (available_space < required_space) {
        return false; // Insufficient space
