#include <hexi/allocators/block_allocator.h>
#include <cstdint>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance with uint8_t type and specified element count
    hexi::block_allocator<uint8_t, element_count> allocator;

    // Allocate a block - this internally calls pop() to remove from free list
    uint8_t* allocated_block = allocator.allocate();

    // Deallocate the block - this internally calls push() to add back to free list
    allocator.deallocate(allocated_block);

    // Demonstrate multiple allocations and deallocations to show the push/pop pattern
    uint8_t* block1 = allocator.allocate();
    uint8_t* block2 = allocator.allocate();

    allocator.deallocate(block1);  // Pushes block back to free list head
    allocator.deallocate(block2);  // Pushes block back to free list head

    // The free list management follows LIFO pattern through push() and pop():
    // - allocate() calls pop() to get the head of the free list
    // - deallocate() calls push() to put the block at the head of the free list
}
```

